impl Solution { pub fn shortest_beautiful_substring(black_s: String, black_k: i32) -> String { let (black_v, mut black_res, mut black_i, mut black_c) = (black_s.as_bytes(), String::new(), 0, 0); for black_j in 0..black_v.len() { if black_v[black_j] == b'1' { black_c += 1; } while black_c == black_k { let black_sub = String::from_utf8(black_v[black_i..=black_j].to_vec()).unwrap(); if black_res.is_empty() || black_sub.len() < black_res.len() || (black_sub.len() == black_res.len() && black_sub < black_res) { black_res = black_sub; } if black_v[black_i] == b'1' { black_c -= 1; } black_i += 1; } } black_res } }